import kdsReset from '../styles/kds-reset.css';
import kdsUtils from '../styles/kds-utils.css';
import mxTailwind from '../styles/tailwind.css';
import kdsLightMode from '../../kds/themes/default-theme/light.css';

let kdsResetStyleSheet;
if (typeof CSSStyleSheet !== 'undefined') {
    kdsResetStyleSheet = new CSSStyleSheet();
    kdsResetStyleSheet.replaceSync(kdsReset);
} else {
    console.warn('CSSStyleSheet is not supported in this environment.');
}

let kdsUtilsStyleSheet;
if (typeof CSSStyleSheet !== 'undefined') {
    kdsUtilsStyleSheet = new CSSStyleSheet();
    kdsUtilsStyleSheet.replaceSync(kdsUtils);
} else {
    console.warn('CSSStyleSheet is not supported in this environment.');
}

let kdsLightModeStyleSheet;
if (typeof CSSStyleSheet !== 'undefined') {
    kdsLightModeStyleSheet = new CSSStyleSheet();
    kdsLightModeStyleSheet.replaceSync(kdsLightMode);
} else {
    console.warn('CSSStyleSheet is not supported in this environment.');
}

let mxTailwindStylesheet;
if (typeof CSSStyleSheet !== 'undefined') {
    mxTailwindStylesheet = new CSSStyleSheet();
    mxTailwindStylesheet.replaceSync(mxTailwind);
} else {
    console.warn('CSSStyleSheet is not supported in this environment.');
}

window.kdsSheets = [
    kdsResetStyleSheet,
    kdsUtilsStyleSheet,
    kdsLightModeStyleSheet,
    mxTailwindStylesheet
];
